mapper.select:
SELECT dividend_id AS dividendId , stock_cd AS stockCd , ex_date AS exDate , dividend , payment_dt AS paymentDt , reg_dt AS regDt FROM ( SELECT dividend_id , stock_cd , ex_date , dividend , payment_dt , reg_dt , ROW_NUMBER() OVER (PARTITION BY stock_cd ORDER BY ex_date DESC) AS rn FROM tbl_dividend_history WHERE stock_cd IN
#{item}
) ranked WHERE rn <= #{limit} ORDER BY stock_cd, ex_date DESC
